import{_ as e,o as a,c as t,a2 as s}from"./chunks/framework.b3aQeZRM.js";const h=JSON.parse('{"title":"Truncation Debugging","description":"","frontmatter":{},"headers":[],"relativePath":"truncation-debugging.md","filePath":"truncation-debugging.md"}'),n={name:"truncation-debugging.md"};function l(o,i,r,d,c,p){return a(),t("div",null,[...i[0]||(i[0]=[s('<h1 id="truncation-debugging" tabindex="-1">Truncation Debugging <a class="header-anchor" href="#truncation-debugging" aria-label="Permalink to &quot;Truncation Debugging&quot;">​</a></h1><h2 id="likely-causes" tabindex="-1">Likely causes <a class="header-anchor" href="#likely-causes" aria-label="Permalink to &quot;Likely causes&quot;">​</a></h2><ul><li>Relay request-size guard: <code>MAX_REQUEST_BODY_BYTES</code> (default <code>1048576</code>) in <a href="/relay/home/achu/relay/src/config.ts"><code>src/config.ts</code></a> and enforced in <a href="/relay/home/achu/relay/src/server.ts"><code>src/server.ts</code></a>.</li><li>Client-side truncation before Relay (Cline/request builder).</li><li>Relay normalization edge cases in message/tool_result mapping: <ul><li>OpenAI path: <a href="/relay/home/achu/relay/src/internal/openai-chat.ts"><code>src/internal/openai-chat.ts</code></a></li><li>Anthropic path: <a href="/relay/home/achu/relay/src/internal/anthropic-messages.ts"><code>src/internal/anthropic-messages.ts</code></a></li></ul></li><li>Upstream/model behavior: <ul><li><code>max_tokens</code> output cap (not input truncation).</li><li>context-window overflow at llama.cpp/model side.</li><li>long-context attention degradation (model behavior, not transport truncation).</li></ul></li><li>Streaming transport interruptions/malformed SSE (Relay now logs upstream/downstream SSE counts and byte totals).</li></ul><h2 id="enable-diagnostics" tabindex="-1">Enable diagnostics <a class="header-anchor" href="#enable-diagnostics" aria-label="Permalink to &quot;Enable diagnostics&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RELAY_DEBUG_TRUNCATION</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> RELAY_DEBUG_TRUNCATION_CONTENT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">1</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p><code>RELAY_DEBUG_TRUNCATION=1</code> logs:</p><ul><li>inbound request diagnostics (<code>truncation.inbound</code>)</li><li>upstream payload diagnostics (<code>truncation.upstream_payload</code>)</li><li>non-stream response sizes (<code>truncation.response</code>)</li><li>stream event/byte counters (<code>truncation.stream</code>)</li></ul><p><code>RELAY_DEBUG_TRUNCATION_CONTENT=1</code> additionally logs first/last 80 chars for large fields.</p><h2 id="run-synthetic-test-and-script" tabindex="-1">Run synthetic test and script <a class="header-anchor" href="#run-synthetic-test-and-script" aria-label="Permalink to &quot;Run synthetic test and script&quot;">​</a></h2><p>Tests:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --experimental-strip-types</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --test</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tests/truncation-diagnostics.test.ts</span></span></code></pre></div><p>Script:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./scripts/diagnose-truncation.sh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:1234</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /v1/chat/completions</span></span></code></pre></div><h2 id="interpreting-logs" tabindex="-1">Interpreting logs <a class="header-anchor" href="#interpreting-logs" aria-label="Permalink to &quot;Interpreting logs&quot;">​</a></h2><ul><li>Relay-side truncation likely if: <ul><li><code>truncation.inbound</code> already shows missing END marker/fingerprint.</li><li>or inbound looks complete but <code>truncation.upstream_payload</code> loses END marker/fingerprint.</li></ul></li><li>Upstream/model truncation likely if: <ul><li>inbound and upstream payload fingerprints are complete, but output stops early and stream/non-stream size logs are consistent with full input transit.</li></ul></li><li>llama.cpp context overflow likely if: <ul><li>full payload reaches upstream, then generation ends with short/empty output, <code>length</code> stop reason, or unstable output quality at high context usage.</li></ul></li><li>Model attention failure likely if: <ul><li>full payload reaches upstream but semantically ignores tail sections despite no transport truncation.</li></ul></li></ul><h2 id="existing-limits-and-assumptions-found" tabindex="-1">Existing limits and assumptions found <a class="header-anchor" href="#existing-limits-and-assumptions-found" aria-label="Permalink to &quot;Existing limits and assumptions found&quot;">​</a></h2><ul><li>Request body hard cap: <code>MAX_REQUEST_BODY_BYTES</code> (default 1 MiB).</li><li>Pre-read <code>Content-Length</code> checked before body read; body read is also counted incrementally.</li><li>No explicit input string slicing in request normalization paths.</li><li>Observability request snapshots intentionally summarize/truncate previews (does not affect forwarding behavior).</li></ul>',17)])])}const g=e(n,[["render",l]]);export{h as __pageData,g as default};
